#!/usr/bin/env node

/**
 * Generates example/src/devTelemetryConfig.ts from environment variables or
 * a .env file. The generated file is gitignored — never committed.
 *
 * Reads from:
 *   1. Environment variables
 *   2. .env file in the project root (fallback)
 *
 * Variables (same as inject-telemetry-config):
 *   BOLT_OTLP_ENDPOINT   (optional, defaults to Grafana Cloud prod)
 *   BOLT_OTLP_USERNAME   Grafana Cloud instance/user ID
 *   BOLT_OTLP_AUTH_TOKEN Grafana Cloud API key (raw, not pre-encoded)
 *
 * Usage:
 *   yarn gen-dev-telemetry-config
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, '..');
const ENV_FILE = path.join(ROOT, '.env');
const OUT_FILE = path.join(ROOT, 'example', 'src', 'devTelemetryConfig.ts');

const DEFAULT_ENDPOINT = 'https://otlp-gateway-prod-us-west-0.grafana.net/otlp';

// Load .env file if present (simple key=value parser)
const loadDotEnv = () => {
  if (!fs.existsSync(ENV_FILE)) return;
  const content = fs.readFileSync(ENV_FILE, 'utf8');
  for (const line of content.split('\n')) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) continue;
    const eqIdx = trimmed.indexOf('=');
    if (eqIdx === -1) continue;
    const key = trimmed.slice(0, eqIdx).trim();
    const value = trimmed
      .slice(eqIdx + 1)
      .trim()
      .replace(/^["']|["']$/g, '');
    if (!process.env[key]) {
      process.env[key] = value;
    }
  }
};

loadDotEnv();

const endpoint = process.env.BOLT_OTLP_ENDPOINT ?? DEFAULT_ENDPOINT;
const username = process.env.BOLT_OTLP_USERNAME;
const authToken = process.env.BOLT_OTLP_AUTH_TOKEN;

if (!username || !authToken) {
  console.error(
    'ERROR: BOLT_OTLP_USERNAME and BOLT_OTLP_AUTH_TOKEN must be set.'
  );
  console.error('Add them to a .env file in the project root.');
  process.exit(1);
}

const content = `// Generated by scripts/gen-dev-telemetry-config.js — do not commit.
// Run \`yarn gen-dev-telemetry-config\` to regenerate from .env.
// Set enabled: false to turn off telemetry locally without touching App.tsx.
export const devTelemetryConfig = {
  enabled: true,
  endpoint: '${endpoint}',
  username: '${username}',
  authToken: '${authToken}',
} as const;
`;

fs.writeFileSync(OUT_FILE, content, 'utf8');
console.log('Generated', OUT_FILE);
